import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { ElectionService } from '../../services/election.service';
import { PositionService } from '../../services/position.service';
import { CandidateService } from '../../services/candidate.service';
import { VoteService } from '../../services/vote.service';
import { Election, Position, Candidate } from '../../models/models';

@Component({
  selector: 'app-election-detail',
  templateUrl: './election-detail.component.html',
  styleUrls: ['./election-detail.component.css']
})
export class ElectionDetailComponent implements OnInit {
  election: Election | null = null;
  positions: Position[] = [];
  candidatesByPosition: Map<number, Candidate[]> = new Map();
  selectedCandidates: Map<number, number> = new Map(); // positionId -> candidateId
  loading = true;
  submitting = false;
  error = '';
  success = '';

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private electionService: ElectionService,
    private positionService: PositionService,
    private candidateService: CandidateService,
    private voteService: VoteService
  ) { }

  ngOnInit(): void {
    const electionId = Number(this.route.snapshot.paramMap.get('id'));
    this.loadElectionDetails(electionId);
  }

  loadElectionDetails(electionId: number): void {
    this.loading = true;

    this.electionService.getElectionById(electionId).subscribe({
      next: (response) => {
        if (response.success) {
          this.election = response.data;
          this.loadPositions(electionId);
        }
      },
      error: (error) => {
        this.error = 'Failed to load election details';
        this.loading = false;
      }
    });
  }

  loadPositions(electionId: number): void {
    this.positionService.getPositionsByElection(electionId).subscribe({
      next: (response) => {
        if (response.success) {
          this.positions = response.data;
          this.loadCandidates();
        }
      },
      error: (error) => {
        this.error = 'Failed to load positions';
        this.loading = false;
      }
    });
  }

  loadCandidates(): void {
    let loadedCount = 0;

    this.positions.forEach(position => {
      this.candidateService.getCandidatesByPosition(position.id).subscribe({
        next: (response) => {
          if (response.success) {
            this.candidatesByPosition.set(position.id, response.data);
          }
          loadedCount++;
          if (loadedCount === this.positions.length) {
            this.loading = false;
          }
        },
        error: (error) => {
          loadedCount++;
          if (loadedCount === this.positions.length) {
            this.loading = false;
          }
        }
      });
    });
  }

  selectCandidate(positionId: number, candidateId: number): void {
    this.selectedCandidates.set(positionId, candidateId);
  }

  isSelected(positionId: number, candidateId: number): boolean {
    return this.selectedCandidates.get(positionId) === candidateId;
  }

  getCandidates(positionId: number): Candidate[] {
    return this.candidatesByPosition.get(positionId) || [];
  }

  submitVotes(): void {
    if (this.selectedCandidates.size === 0) {
      this.error = 'Please select at least one candidate';
      return;
    }

    this.submitting = true;
    this.error = '';
    this.success = '';

    const votes = Array.from(this.selectedCandidates.values());
    let votedCount = 0;
    let hasError = false;

    votes.forEach(candidateId => {
      this.voteService.submitVote(candidateId).subscribe({
        next: (response) => {
          votedCount++;
          if (votedCount === votes.length && !hasError) {
            this.success = 'Votes submitted successfully!';
            this.submitting = false;
            setTimeout(() => {
              this.router.navigate(['/elections', this.election?.id, 'results']);
            }, 2000);
          }
        },
        error: (error) => {
          hasError = true;
          this.error = error.error?.message || 'Failed to submit votes';
          this.submitting = false;
        }
      });
    });
  }

  viewResults(): void {
    this.router.navigate(['/elections', this.election?.id, 'results']);
  }
}
<div class="election-detail-container">
  <app-navbar></app-navbar>

  <div class="content">
    <div class="loading" *ngIf="loading">
      <div class="spinner-large"></div>
      <p>Loading election details...</p>
    </div>

    <div *ngIf="!loading && election">
      <div class="election-header">
        <button class="btn-back" routerLink="/">← Back to Elections</button>
        <h1>{{ election.title }}</h1>
        <p class="description">{{ election.description }}</p>
        <div class="election-status" [class.active]="election.is_active">
          {{ election.is_active ? 'ACTIVE' : 'INACTIVE' }}
        </div>
      </div>

      <div class="alert alert-danger" *ngIf="error">{{ error }}</div>
      <div class="alert alert-success" *ngIf="success">{{ success }}</div>

      <div class="positions-container" *ngIf="!election.is_active">
        <div class="info-message">
          This election is not currently active. You cannot vote at this time.
        </div>
        <button class="btn btn-secondary" (click)="viewResults()">
          View Results
        </button>
      </div>

      <div class="positions-container" *ngIf="election.is_active">
        <div class="position-card" *ngFor="let position of positions">
          <h2>{{ position.name }}</h2>
          <p class="position-description">{{ position.description }}</p>

          <div class="candidates-list">
            <div 
              class="candidate-item"
              *ngFor="let candidate of getCandidates(position.id)"
              [class.selected]="isSelected(position.id, candidate.id)"
              (click)="selectCandidate(position.id, candidate.id)"
            >
              <div class="candidate-avatar">
                {{ candidate.name.charAt(0) }}
              </div>
              <div class="candidate-info">
                <h3>{{ candidate.name }}</h3>
              </div>
              <div class="candidate-select">
                <input 
                  type="radio" 
                  [name]="'position-' + position.id"
                  [checked]="isSelected(position.id, candidate.id)"
                  (click)="$event.stopPropagation()"
                />
              </div>
            </div>
          </div>
        </div>

        <div class="vote-actions" *ngIf="positions.length > 0">
          <button 
            class="btn btn-primary btn-large"
            [disabled]="submitting || selectedCandidates.size === 0"
            (click)="submitVotes()"
          >
            <span *ngIf="submitting" class="spinner"></span>
            <span *ngIf="!submitting">Submit Votes ({{ selectedCandidates.size }} selected)</span>
          </button>
          <button 
            class="btn btn-secondary"
            (click)="viewResults()"
          >
            View Current Results
          </button>
        </div>
      </div>

      <div class="empty-state" *ngIf="positions.length === 0">
        <h3>No Positions Available</h3>
        <p>This election does not have any positions configured yet.</p>
      </div>
    </div>
  </div>
</div>
